@org.springframework.stereotype.Service
class FileStorageService {

    private static final Set<String> ALLOWED_CONTENT_TYPES = Set.of(
            "image/jpeg",
            "image/png",
            "image/gif",
            "image/webp",
            "image/jpg"
    );

    private static final Set<String> ALLOWED_EXTENSIONS = Set.of(
            "jpg", "jpeg", "png", "gif", "webp"
    );

    private static final Pattern SAFE_NAME = Pattern.compile("[^a-zA-Z0-9._-]");
    private final Path uploadRoot = Paths.get("public", "uploads", "profile-pictures").toAbsolutePath().normalize();

    public void init() throws IOException {
        Files.createDirectories(uploadRoot);
    }

    public StoredFile store(MultipartFile file) throws IOException {
        if (file == null || file.isEmpty()) {
            throw new InvalidFileException("File is required");
        }

        String originalFilename = StringUtils.cleanPath(Objects.requireNonNullElse(file.getOriginalFilename(), "file"));
        String extension = getExtension(originalFilename).toLowerCase(Locale.ROOT);

        if (!ALLOWED_EXTENSIONS.contains(extension)) {
            throw new InvalidFileException("Only image files are allowed: jpg, jpeg, png, gif, webp");
        }

        String contentType = Optional.ofNullable(file.getContentType()).orElse("").toLowerCase(Locale.ROOT);
        if (!ALLOWED_CONTENT_TYPES.contains(contentType)) {
            throw new InvalidFileException("Unsupported content type");
        }

        String baseName = originalFilename;
        int dotIndex = originalFilename.lastIndexOf('.');
        if (dotIndex > 0) {
            baseName = originalFilename.substring(0, dotIndex);
        }

        baseName = SAFE_NAME.matcher(baseName).replaceAll("_");
        if (baseName.isBlank()) {
            baseName = "profile";
        }

        String generatedName = baseName + "_" + UUID.randomUUID() + "." + extension;
        Path target = uploadRoot.resolve(generatedName).normalize();

        if (!target.startsWith(uploadRoot)) {
            throw new InvalidFileException("Invalid file path");
        }

        try (InputStream inputStream = file.getInputStream()) {
            Files.copy(inputStream, target, StandardCopyOption.REPLACE_EXISTING);
        }

        return new StoredFile(
                generatedName,
                "/uploads/profile-pictures/" + generatedName,
                contentType,
                file.getSize()
        );
    }

    private String getExtension(String fileName) {
        int index = fileName.lastIndexOf('.');
        return index >= 0 ? fileName.substring(index + 1) : "";
    }
}

